export const dictionary = {
  en: {
    title: "Preferences",
    greeting: "Hello",
  },
  es: {
    title: "Preferencias",
    greeting: "Hola",
  },
} as const;

import { component$, Slot, createContextId, useContextProvider, useStore, useTask$ } from "@builder.io/qwik";
import { routeLoader$, routeAction$, type RequestHandler } from "@builder.io/qwik-city";

export interface PreferencesState {
  theme: "light" | "dark";
  locale: "en" | "es";
}

export const PreferencesContext = createContextId<PreferencesState>("preferences-context");

export const onRequest: RequestHandler = async (event) => {
  const themeCookie = event.cookie.get("theme")?.value;
  const localeCookie = event.cookie.get("locale")?.value;

  const theme = (themeCookie === "light" || themeCookie === "dark") ? themeCookie : "light";
  const locale = (localeCookie === "en" || localeCookie === "es") ? localeCookie : "en";

  event.sharedMap.set("theme", theme);
  event.sharedMap.set("locale", locale);
  event.locale(locale);

  await event.next();
};

export const usePreferences = routeLoader$((event) => {
  const theme = (event.sharedMap.get("theme") as "light" | "dark") || "light";
  const locale = (event.sharedMap.get("locale") as "en" | "es") || "en";
  return { theme, locale };
});

export const useSetPreferences = routeAction$(async (data, event) => {
  const theme = data.theme as string;
  const locale = data.locale as string;

  if (theme === "light" || theme === "dark") {
    event.cookie.set("theme", theme, { path: "/" });
  }
  if (locale === "en" || locale === "es") {
    event.cookie.set("locale", locale, { path: "/" });
  }

  return { success: true };
});

export default component$(() => {
  const preferences = usePreferences();

  const state = useStore<PreferencesState>({
    theme: preferences.value.theme,
    locale: preferences.value.locale,
  });

  useTask$(({ track }) => {
    track(() => preferences.value);
    state.theme = preferences.value.theme;
    state.locale = preferences.value.locale;
  });

  useContextProvider(PreferencesContext, state);

  return <Slot />;
});

import { component$, useContext } from "@builder.io/qwik";
import { Form } from "@builder.io/qwik-city";
import { PreferencesContext, useSetPreferences } from "./layout";
import { dictionary } from "../i18n";

export default component$(() => {
  const state = useContext(PreferencesContext);
  const setPreferences = useSetPreferences();

  const t = dictionary[state.locale];

  return (
    <main style={{ padding: "2rem", fontFamily: "system-ui, sans-serif" }}>
      <h1>{t.title}</h1>
      <p>{t.greeting}</p>

      <Form action={setPreferences} style={{ marginTop: "1.5rem", display: "flex", flexDirection: "column", gap: "1rem", maxWidth: "300px" }}>
        <div style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
          <label for="theme" style={{ fontWeight: "bold" }}>Theme</label>
          <select id="theme" name="theme" value={state.theme} style={{ padding: "0.5rem", borderRadius: "4px", border: "1px solid #ccc" }}>
            <option value="light">Light</option>
            <option value="dark">Dark</option>
          </select>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: "0.25rem" }}>
          <label for="locale" style={{ fontWeight: "bold" }}>Language</label>
          <select id="locale" name="locale" value={state.locale} style={{ padding: "0.5rem", borderRadius: "4px", border: "1px solid #ccc" }}>
            <option value="en">English</option>
            <option value="es">Español</option>
          </select>
        </div>
        <button type="submit" style={{ padding: "0.5rem 1rem", backgroundColor: "#0070f3", color: "white", border: "none", borderRadius: "4px", cursor: "pointer", fontWeight: "bold" }}>
          Save
        </button>
      </Form>
    </main>
  );
});

/**
 * WHAT IS THIS FILE?
 *
 * SSR entry point, in all cases the application is rendered outside the browser, this
 * entry point will be the common one.
 *
 * - Server (express, cloudflare...)
 * - npm run start
 * - npm run preview
 * - npm run build
 *
 */
import {
  renderToStream,
  type RenderToStreamOptions,
} from "@builder.io/qwik/server";
import Root from "./root";

function getCookieValue(cookieHeader: string, name: string): string | undefined {
  if (!cookieHeader) return undefined;
  const cookies = cookieHeader.split(";");
  for (const cookie of cookies) {
    const [key, val] = cookie.trim().split("=");
    if (key === name) {
      return decodeURIComponent(val);
    }
  }
  return undefined;
}

export default function (opts: RenderToStreamOptions) {
  const cookieHeader = opts.serverData?.requestHeaders?.cookie || opts.serverData?.requestHeaders?.Cookie || "";
  const themeCookie = getCookieValue(cookieHeader, "theme");
  const theme = (themeCookie === "light" || themeCookie === "dark") ? themeCookie : "light";

  const localeCookie = getCookieValue(cookieHeader, "locale");
  const locale = opts.serverData?.locale || (localeCookie === "en" || localeCookie === "es" ? localeCookie : "en");

  return renderToStream(<Root />, {
    ...opts,
    // Use container attributes to set attributes on the html tag.
    containerAttributes: {
      lang: locale,
      "data-theme": theme,
      ...opts.containerAttributes,
    },
    serverData: {
      ...opts.serverData,
    },
  });
}

